window.addEventListener("load",()=>{const e=document.querySelector(".referral");if(!e)return;e.style.setProperty("display","none","important");const t=new MutationObserver(()=>{e.style.setProperty("display","none","important"),document.querySelectorAll(".juicer-about").forEach(e=>{e.style.setProperty("display","none","important")})});t.observe(e,{attributes:!0,attributeFilter:["style"]})});